const e=[{id:1,section:"处罚罚款",sectionName:"处罚罚款",category:"处罚罚款",question:"的士车主及司机若未能确保的士计程表的装置符合法例要求，或署长的印章不完好，最高可面临什么处罚？",options:["罚款$5,000及监禁3个月","罚款$10,000及监禁6个月","罚款$25,000及监禁12个月"],correctAnswer:1,explanation:"根据小册子第一部分“的士计程表”规定，车主及司机有责任确保计程表符合要求且印章完好，否则即属违法，可被处罚款$10,000及监禁6个月。"},{id:2,section:"处罚罚款",sectionName:"处罚罚款",category:"处罚罚款",question:"任何人无理地损坏或更改的士计程表，如属“再次定罪（重犯）”，最高可被判处什么刑罚？",options:["罚款$10,000及监禁6个月","罚款$20,000及监禁9个月","罚款$25,000及监禁12个月"],correctAnswer:2,explanation:"根据小册子第一部分规定，损坏或更改的士计程表属违法行为。首次定罪罚款$10,000及监禁6个月；再次定罪（重犯）则提高至罚款$25,000及监禁12个月。"},{id:3,section:"处罚罚款",sectionName:"处罚罚款",category:"处罚罚款",question:"法例规定收据打印设备在良好运作下应能在几秒内打印出车费收据？若的士车主不遵从相关设备的规定，最高可被处罚款$10,000及监禁6个月？",options:["10秒","12秒","15秒"],correctAnswer:1,explanation:"根据第二部分“收据打印设备”规定，该设备在良好运作下应能在12秒内打印出一张车费收据。的士车主如不遵从法例上有关车费收据打印设备的规定，最高可被处罚款$10,000及监禁6个月。"},{id:4,section:"处罚罚款",sectionName:"处罚罚款",category:"处罚罚款",question:"的士司机如不遵从有关“发出车费收据”的法例（例如拒绝发出收据），最高可被处罚：",options:["罚款$5,000及监禁6个月","罚款$10,000及监禁6个月","定额罚款港币600元"],correctAnswer:0,explanation:"根据第二部分规定，的士司机如不遵从有关发出车费收据的法例，最高可被罚款$5,000及监禁6个月。"},{id:5,section:"处罚罚款",sectionName:"处罚罚款",category:"处罚罚款",question:"任何人无合法权限或合理辩解而毁损、损坏、拆除认可的行车记录系统，或破坏其封条，一经定罪最高可处：",options:["罚款$5,000及监禁1个月","罚款$10,000及监禁6个月","罚款$25,000及监禁12个月"],correctAnswer:1,explanation:"根据第三部分“行车记录系统”法例规定，违反规定即属犯罪，一经定罪，可处罚款$10,000及监禁6个月。"},{id:6,section:"处罚罚款",sectionName:"处罚罚款",category:"处罚罚款",question:"非车队的士（一般的士）若违反规定，在指定的“车队的士停车处”停留或上落乘客，违规司机一经检控会被判处：",options:["定额罚款港币320元","定额罚款港币450元","定额罚款港币600元"],correctAnswer:2,explanation:"根据第九部分“的士车队”规定，一般的士均不得在车队的士停车处停留或上落乘客。根据《定额罚款（刑事诉讼）条例》，违规司机一经检控，会被定额罚款港币600元。"},{id:7,section:"处罚罚款",sectionName:"处罚罚款",category:"处罚罚款",question:"若的士司机无合理辩解，未能在指定限期内自费修习和完成“的士服务改进课程”，一经定罪最高可处什么刑罚？",options:["第1级罚款（港币2,000元）及监禁14天","第2级罚款（港币5,000元）及监禁1个月","第3级罚款（港币10,000元）及监禁6个月"],correctAnswer:1,explanation:"根据第十五部分“的士司机违例记分制度”规定，任何人无合理辩解而没有在指定限期内修习和完成课程，一经定罪，可处第2级罚款（即港币5,000元）及监禁1个月。"},{id:8,section:"处罚罚款",sectionName:"处罚罚款",category:"处罚罚款",question:"根据违例记分制，当的士司机在任何2年期间内累计被记的分数达到多少分或以上时，可被取消驾驶的士资格（停牌）？",options:["10分","15分","20分"],correctAnswer:1,explanation:"根据第十五部分（3）规定，当的士司机在任何2年期间内被记分数累计达15分或以上，可按法例规定被取消驾驶的士资格。"},{id:9,section:"处罚罚款",sectionName:"处罚罚款",category:"处罚罚款",question:"在的士司机违例记分制度下，若司机在2年内累计被记满15分或以上而被取消驾驶的士资格，法庭颁令的首次停牌期以及其后再被停牌的期限分别是多久？",options:["首次停牌1个月，其后再停牌每次为期3个月","首次停牌3个月，其后再停牌每次为期6个月","首次停牌6个月，其后再停牌每次为期12个月"],correctAnswer:1,explanation:"根据第十五部分（3）明确规定：在任何2年期间内被记15分或以上而被取消驾驶资格，如属首次被取消驾驶的士资格，停牌期为三个月；其后再被停牌则每次为期六个月，以法庭颁发的命令为准。"},{id:10,section:"处罚罚款",sectionName:"处罚罚款",category:"处罚罚款",question:"根据的士司机违例记分制度，干犯以下哪一组严重罪行会被直接记 10 分，并且重犯者的罚款上限及最高监禁期会提高至第四级罚款（$25,000）和监禁 12 个月？",options:["滥收车费、故意拒绝或忽略接受租用、拒绝或忽略驾驶的士至租用人指示的地方、毁损/损坏/更改的士计程表","兜客、没有采用最直接路线（兜路）、未经同意允许他人登车（钓泥鯭）","拒绝或忽略发出收据、没有将的士计程表设定于记录位置"],correctAnswer:0,explanation:"根据第十五部分及附录己，只有滥收车费、拒载、不按指示驶往目的地、损坏或更改计程表这4项罪行给予10分，且触发两级制罚则（初犯第三级罚款及监禁6个月，重犯提高至第四级罚款及监禁12个月）。"},{id:11,section:"处罚罚款",sectionName:"处罚罚款",category:"处罚罚款",question:"在任何2年期间内，的士司机被记分数达到什么水平时，运输署署长会向其发出“强制修习的士服务改进课程通知”？",options:["达 5 分或以上","达 8 分或以上","达 10 分或以上"],correctAnswer:2,explanation:"记录显示根据第十五部分（2）规定，被记分数达10分 or 以上时，司机会收到通知，并须在通知日期起计的3个月内自费修习和完成的士服务改进课程。"},{id:12,section:"处罚罚款",sectionName:"处罚罚款",category:"处罚罚款",question:"根据违例记分制，以下哪项违例行为属于被记 5 分的级别？",options:["没有将的士计程表设定于记录位置","没有采用最直接而切实可行的路线驶往目的地（俗称“兜路”）","拒绝或忽略发出收据"],correctAnswer:1,explanation:"根据附录己的记分表，“没有采用最直接而切实可行的路线驶往目的地（俗称‘兜路’）”属于给予5分的罪行。"},{id:13,section:"处罚罚款",sectionName:"处罚罚款",category:"处罚罚款",question:"的士司机如果干犯“未经租用人同意，允许租用人以外的任何人登上的士（俗称‘钓泥鯭’）”，在记分制度下会被记几分？",options:["3分","5分","10分"],correctAnswer:1,explanation:"根据附录己第7项罪行，“未经租用人同意，允许租用人以外的任何人登上的士”会被记5分。"},{id:14,section:"处罚罚款",sectionName:"处罚罚款",category:"处罚罚款",question:"以下哪一项属于被记 5 分的的士司机违例罪行？",options:["兜客","滥收车费","拒绝或忽略发出收据"],correctAnswer:0,explanation:"根据附录己第5项，“兜客”在记分制中被划分为给予5分的罪行。"},{id:15,section:"处罚罚款",sectionName:"处罚罚款",category:"处罚罚款",question:"根据的士司机违例记分制度，干犯以下哪组轻微违例行为会被记 3 分？",options:["兜客、欺骗或拒绝知会乘客适当车费","拒绝或忽略发出收据、没有将的士计程表设定于记录位置","故意拒绝接受租用、拒绝运载租用人要求数目的乘客"],correctAnswer:1,explanation:"根据附录己第10及11项，最低一级的记分罪行为3分，分别是“拒绝或忽略发出收据”以及“没有将的士计程表设定于记录位置”。"},{id:16,section:"处罚罚款",sectionName:"处罚罚款",category:"处罚罚款",question:"根据记分制，若的士司机干犯“欺骗或拒绝知会乘客或有意乘车的人有关适当的收费及前往某处的路线”以及“拒绝或忽略运载租用人要求数目的乘客”，分别会被记几分？",options:["前者记 10 分，后者记 5 分","前者记 5 分，后者记 3 分","两项均记 5 分"],correctAnswer:1,explanation:"根据香港《的士司机违例记分条例》（第647章），11项违例罪行按严重性划分为三级。其中“欺骗或拒绝知会乘客有关适当收费及路线”属于5分罪行；而“拒绝或忽略运载租用人要求数目的乘客”属于3分罪行。因此前者记 5 分，后者记 3 分。"}],o=Object.freeze(Object.defineProperty({__proto__:null,default:e},Symbol.toStringTag,{value:"Module"}));export{o as _};
